INSERT INTO margin_analyses (product_id, supplier_price, shipping_cost, platform_fee_pct, payment_fee_pct, ad_spend_estimate, return_rate_pct, selling_price, gross_profit, gross_margin_pct, net_profit, net_margin_pct, roi_pct, break_even_units, verdict, ai_analysis) VALUES
  ('b1000000-0000-0000-0000-000000000001', 8.50, 3.20, 13.0, 2.9, 3.50, 5.0, 34.99, 23.29, 66.56, 11.96, 34.18, 102.22, 4, 'excellent', 'Strong wireless charging product with excellent margin. Rising search trend and multiple platform opportunities make this ideal for scaling.'),
  ('b1000000-0000-0000-0000-000000000002', 18.90, 4.50, 13.0, 2.9, 8.00, 5.0, 79.99, 56.59, 70.75, 36.98, 46.23, 161.22, 2, 'excellent', 'Premium ANC earbuds with exceptional margin at 46%. High search volume of 45K monthly with rising trend — top opportunity for dropshipping.'),
  ('b1000000-0000-0000-0000-000000000003', 6.20, 2.80, 13.0, 2.9, 2.50, 5.0, 24.99, 16.00, 64.03, 8.67, 34.70, 96.22, 3, 'excellent', 'High-margin phone accessory with consistent demand. Low competition barrier and stable trend make this reliable for portfolio.'),
  ('b1000000-0000-0000-0000-000000000004', 7.80, 3.50, 13.0, 2.9, 3.00, 5.0, 32.99, 21.69, 65.75, 11.44, 34.68, 100.35, 4, 'excellent', 'Solar fairy lights seeing strong seasonal uplift. Home & garden category growing 28% YoY in AU market. Excellent margin profile.'),
  ('b1000000-0000-0000-0000-000000000005', 12.40, 4.20, 13.0, 2.9, 5.00, 5.0, 49.99, 33.39, 66.79, 18.05, 36.11, 109.45, 3, 'excellent', 'Sustainable herb garden kit aligns with growing wellness trend. 9.2K monthly searches with rising trend and 36% net margin.'),
  ('b1000000-0000-0000-0000-000000000006', 9.60, 3.80, 13.0, 2.9, 4.00, 5.0, 39.99, 26.59, 66.49, 13.90, 34.76, 104.03, 3, 'excellent', 'Eco-friendly bathroom organiser fits perfectly into sustainability trend. Good margin and stable demand create reliable revenue stream.'),
  ('b1000000-0000-0000-0000-000000000007', 22.50, 6.80, 13.0, 2.9, 9.00, 5.0, 89.99, 60.69, 67.44, 32.60, 36.23, 111.97, 3, 'excellent', 'Smart pet feeder is a high-ticket winner with rising pet ownership in AU. 32K monthly searches trending upward strongly.'),
  ('b1000000-0000-0000-0000-000000000008', 11.20, 4.20, 13.0, 2.9, 3.50, 5.0, 34.99, 19.59, 55.99, 9.65, 27.58, 63.49, 5, 'good', 'Dog leash in competitive but stable market. Decent margin at 27%. Consider bundling with collar or treats to improve average order value.'),
  ('b1000000-0000-0000-0000-000000000009', 28.90, 8.50, 13.0, 2.9, 12.00, 5.0, 119.99, 82.59, 68.83, 42.42, 35.35, 113.93, 3, 'excellent', 'Premium pet bed is a strong high-ticket item. Rising pet humanisation trend drives demand. Excellent ROI at 113%.'),
  ('b1000000-0000-0000-0000-000000000010', 9.80, 3.50, 13.0, 2.9, 4.00, 5.0, 39.99, 26.69, 66.74, 13.63, 34.08, 102.46, 4, 'excellent', 'Fitness category exploding post-pandemic. 52K monthly searches with rising trend. Resistance bands are consistently top sellers.'),
  ('b1000000-0000-0000-0000-000000000011', 7.20, 3.80, 13.0, 2.9, 3.00, 5.0, 29.99, 19.00, 63.35, 9.91, 33.04, 90.94, 4, 'excellent', 'Foam rollers are staple fitness recovery tools. Stable demand with good margin makes this a reliable catalogue item.'),
  ('b1000000-0000-0000-0000-000000000012', 4.80, 2.50, 13.0, 2.9, 2.50, 5.0, 24.99, 17.69, 70.79, 10.26, 41.06, 139.73, 3, 'excellent', 'Jade roller is a high-margin beauty impulse purchase. 38K monthly searches with strong rising trend — top beauty opportunity.'),
  ('b1000000-0000-0000-0000-000000000013', 14.50, 4.80, 13.0, 2.9, 7.00, 5.0, 69.99, 50.69, 72.42, 28.25, 40.36, 145.24, 3, 'excellent', 'LED face mask is premium beauty tech with excellent 40% net margin. Social media driven demand creating viral growth potential.'),
  ('b1000000-0000-0000-0000-000000000014', 6.90, 3.20, 13.0, 2.9, 3.00, 5.0, 29.99, 19.89, 66.32, 10.91, 36.38, 108.53, 3, 'excellent', 'K-beauty vitamin C serum riding the Korean skincare wave. 42K monthly searches with 36% net margin and rising trend.'),
  ('b1000000-0000-0000-0000-000000000015', 8.20, 3.00, 13.0, 2.9, 3.50, 5.0, 34.99, 23.79, 67.99, 12.70, 36.30, 113.39, 4, 'excellent', 'Electric eyelash curler is a unique beauty gadget with low supplier cost and high perceived value. Strong impulse purchase potential.');
